   275→		[NFP_NET_CFG_STS_LINK_RATE_UNKNOWN]	= SPEED_UNKNOWN,
   276→		[NFP_NET_CFG_STS_LINK_RATE_1G]		= SPEED_1000,
   277→		[NFP_NET_CFG_STS_LINK_RATE_10G]		= SPEED_10000,
   278→		[NFP_NET_CFG_STS_LINK_RATE_25G]		= SPEED_25000,
   279→		[NFP_NET_CFG_STS_LINK_RATE_40G]		= SPEED_40000,
   280→		[NFP_NET_CFG_STS_LINK_RATE_50G]		= SPEED_50000,
   281→		[NFP_NET_CFG_STS_LINK_RATE_100G]	= SPEED_100000,
   282→	};
