   307→	/* Use link speed from ETH table if available, otherwise try the BAR */
   308→	if (eth_port) {
   309→		cmd->base.port = eth_port->port_type;
   310→		cmd->base.speed = eth_port->speed;
   311→		cmd->base.duplex = DUPLEX_FULL;
   312→		return 0;
