   340→	struct nfp_port *port;
   341→	struct nfp_nsp *nsp;
   342→	int err;
   343→
   344→	port = nfp_port_from_netdev(netdev);
   345→	eth_port = __nfp_port_get_eth_port(port);
   346→	if (!eth_port)
   347→		return -EOPNOTSUPP;
   348→
   349→	if (netif_running(netdev)) {
   350→		netdev_warn(netdev, "Changing settings not allowed on an active interface. It may cause the port to be disabled until driver reload.\n");
   351→		return -EBUSY;
   352→	}
   353→
   354→	nsp = nfp_eth_config_start(port->app->cpp, eth_port->index);
   355→	if (IS_ERR(nsp))
   356→		return PTR_ERR(nsp);
   357→
   358→	err = __nfp_eth_set_aneg(nsp, cmd->base.autoneg == AUTONEG_ENABLE ?
   359→				 NFP_ANEG_AUTO : NFP_ANEG_DISABLED);
   360→	if (err)
   361→		goto err_bad_set;
